import type { AudioEffect } from "./BaseEffect.js";
import { clampVolume } from "./utils.js";

export class VolumeEffect implements AudioEffect {
  readonly name = "volume";
  private _volume: number;

  constructor(volume: number) {
    this._volume = clampVolume(volume);
  }

  get volume(): number {
    return this._volume;
  }

  setVolume(v: number): void {
    this._volume = clampVolume(v);
  }

  isActive(): boolean {
    return this._volume !== 1;
  }

  process(samples: Float64Array, _channels: number, _frames: number): void {
    if (this._volume === 1) return;
    const vol = this._volume;
    for (let i = 0; i < samples.length; i++) {
      samples[i] = samples[i]! * vol;
    }
  }

  reset(): void {
    // no state
  }
}
